scwin.f_downExcelSheet = async function () {

    let vObjGrd;
    let sheetTitle;
    let cntRow = ds_containerBookingList.getTotalRow();

    if (cntRow != "0") {
        let cfrm = await $c.win.confirm("Freight Charge Code List를 EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            // vObjGrd = "gr_item";
            // sheetTitle = "Freight Charge Code List";
            let excelName = "Freight Charge Code List"
            // let objGrd = $p.getComponentById(vObjGrd);
            // cfGridToExcel(objGrd, sheetTitle, sheetTitle, 2 + 4 + 8 + 16);

            const grdObj = "gr_item";
            const infoArr = [];
            const options = {
                fileName: excelName, //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                sheetName: excelName
            };
            $c.data.downloadGridViewExcel(grdObj, options, infoArr);

        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.  
    }
}

