        let codeVal = ds_departmentInfo.getCellData(rowPos, "CODE")
        let nameVal = ds_departmentInfo.getCellData(rowPos, "NAME")
        ed_dept.setValue(codeVal);
        txt_deptnm.setValue(nameVal);
    }
};

