    // inputCalendar에 달려있는 달력 버튼 (asis에는 있는데 tobe에는 버튼 id를 줄수없어 주석처리함)
    // $c.gus.cfDisableObjects([img_Date1, img_Date2, img_Date3]); 

    $c.gus.cfDisableObjects(
        [
            img_PopUp1,
            img_PopUp2,
            img_PopUp3,
            img_PopUp4,
            img_PopUpSub3,
            img_PopUpSub4,
            img_PopUp5,
