};

scwin.date_Formatter = function (value) {
    if (!value) return "";

    value = String(value).replace(/[^0-9]/g, "");

    if (value.length === 4) {
        return value.substring(0, 4) + "/"
            + value.substring(4, 6) + " / "
            + value.substring(6, 8) + "  -  :  ";
    }

    if (value.length === 6) {
        return value.substring(0, 4) + "/"
            + value.substring(4, 6) + "/ "
            + value.substring(6, 8) + "  -  :  ";
    }

    // 날짜만 들어온 경우: yyyyMMdd
    if (value.length === 8) {
        return value.substring(0, 4) + "/"
            + value.substring(4, 6) + "/"
            + value.substring(6, 8) + " -  :  ";
    }

    // 날짜+시간까지 들어온 경우: yyyyMMddHHmm
    if (value.length >= 12) {
        return value.substring(0, 4) + "/"
            + value.substring(4, 6) + "/"
            + value.substring(6, 8) + "-"
            + value.substring(8, 10) + "  :  "
            + value.substring(10, 12);
    }

    return value;
};


scwin.sendData_formatter = function (value) {
    if (!value) return "";

    value = String(value).replace(/[^0-9]/g, "");

    if (value.length === 4) {
        return value.substring(0, 4) + "/"
            + value.substring(4, 6) + " / "
            + value.substring(6, 8) + " / ";
    }

    if (value.length === 6) {
        return value.substring(0, 4) + "/"
            + value.substring(4, 6) + "/"
            + value.substring(6, 8) + " / ";
    }

    if (value.length === 8) {
        return value.substring(0, 4) + "/"
            + value.substring(4, 6) + "/"
            + value.substring(6, 8) + "/";
    }

    return value;
}
